    // Load file index from cache
    $outputDir = $settings['output_dir'];
    if (!preg_match('/^(?:[A-Za-z]:[\\/]|\/)/', $outputDir)) {
        $outputDir = dirname(__FILE__) . '/' . $outputDir;
    }
    $indexFile = rtrim($outputDir, '/\\') . '/.file_index.json';
    if (!file_exists($indexFile)) {
        echo json_encode(['error' => 'File index not found. Please regenerate documentation.']);
        exit;
    }

    $fileIndex = json_decode(file_get_contents($indexFile), true);
    if (!isset($fileIndex[$fileId])) {
        echo json_encode(['error' => 'Invalid file ID']);
        exit;
    }

    $realFile = $fileIndex[$fileId];

    // Security: validate file exists and is PHP
    if (!file_exists($realFile) || pathinfo($realFile, PATHINFO_EXTENSION) !== 'php') {
        echo json_encode(['error' => 'File not accessible']);
        exit;
    }

    // Read file and extract lines
    $lines = file($realFile);
    $sourceLines = array_slice($lines, $lineStart - 1, $lineEnd - $lineStart + 1);
    $source = implode('', $sourceLines);

    echo json_encode([
        'success' => true,
        'source' => $source,
        'file' => basename($realFile),
        'lines' => "$lineStart-$lineEnd"
    ]);
    exit;
}


