}/**
 * Module 18: JSON Index Generator
 * Generates file-index.json with all documentation URLs and structure
 */

trait JsonIndexModule
{
    private function generateJsonIndex() {
        $this->output("📄 Generating JSON file index...");

        $index = [
            'generated' => date('Y-m-d H:i:s'),
            'version' => self::VERSION,
            'total_files' => count($this->files),
            'total_classes' => count($this->allClasses),
            'total_functions' => count($this->allFunctions),
            'base_url' => $this->settings['output_dir'],
            'files' => []
        ];

        foreach ($this->documentation as $file => $doc) {
            $relativePath = $this->getRelativePath($file);
            $htmlPath = str_replace('.php', '_php', $relativePath) . '.html';

            $fileData = [
                'name' => basename($file),
                'path' => $relativePath,
                'url' => $htmlPath,
                'classes' => []
            ];

            // Add classes with their methods
            foreach ($doc['classes'] as $class) {
                $classData = [
                    'name' => $class['name'],
                    'methods' => []
                ];

                // Add methods to class
                foreach ($class['methods'] as $method) {
                    $classData['methods'][] = $method['name'];
                }

                $fileData['classes'][] = $classData;
            }

            // Add standalone functions (outside classes)
            $fileData['functions'] = [];
            foreach ($doc['functions'] as $function) {
                $fileData['functions'][] = $function['name'];
            }

            $index['files'][] = $fileData;
        }

        $jsonFile = $this->settings['output_dir'] . '/file-index.json';
        file_put_contents($jsonFile, json_encode($index, JSON_PRETTY_PRINT | JSON_UNESCAPED_SLASHES | JSON_UNESCAPED_UNICODE));

        $this->output("   ✓ JSON index saved (" . count($index['files']) . " files)");

        $fileIdIndexFile = $this->settings['output_dir'] . '/.file_index.json';
        file_put_contents($fileIdIndexFile, json_encode($this->fileIndex, JSON_UNESCAPED_SLASHES | JSON_UNESCAPED_UNICODE));

        $this->output("   ✓ File ID index saved (" . count($this->fileIndex) . " files)");
    }
}/**
 * Module 08: Scanner
 * Trait containing scanner-related methods for phpDocGenerator
 */

trait ScannerModule
{
    private function findFunctionEnd($tokens, $startIndex)
    {
        $braceCount = 0;
        $foundStart = false;

        for ($i = $startIndex; $i < count($tokens); $i++) {
            if ($tokens[$i] === '{') {
                $braceCount++;
                $foundStart = true;
            } elseif ($tokens[$i] === '}') {
                $braceCount--;
                if ($foundStart && $braceCount === 0) {
                    // Find the line number after closing brace
                    // Look ahead for next token with line info
                    for ($j = $i + 1; $j < count($tokens); $j++) {
                        if (is_array($tokens[$j]) && isset($tokens[$j][2])) {
                            return $tokens[$j][2];
                        }
                    }
                    // Fallback: try to get line from previous token
                    for ($j = $i - 1; $j >= 0; $j--) {
                        if (is_array($tokens[$j]) && isset($tokens[$j][2])) {
                            return $tokens[$j][2] + 1; // Add 1 to include closing brace line
                        }
                    }
                    return 0;
                }
            }
        }

        return 0;
    }

    private function scanDirectories()
    {
        $this->output("📂 Scanning directories...");
        foreach ($this->settings['directories'] as $dir) {
            if (!is_dir($dir)) {
                $this->output("⚠️  Directory does not exist: $dir");
                continue;
            }
            $this->scanDirectory($dir);
        }
        $this->output("   Found " . count($this->files) . " PHP files");
        $this->output("");
    }

    private function scanDirectory($dir)
    {
        $items = scandir($dir);
        foreach ($items as $item) {
            if ($item === '.' || $item === '..') continue;

            $path = $dir . DIRECTORY_SEPARATOR . $item;

            if (is_dir($path)) {
                $skip = false;
                if (!empty($this->settings['exclude_dirs'])) {
                    foreach ($this->settings['exclude_dirs'] as $exclude) {
                        if (strpos($path, $exclude) !== false) {
                            $skip = true;
                            break;
                        }
                    }
                }
                if (!$skip) {
                    $this->scanDirectory($path);
                }
            } elseif (pathinfo($path, PATHINFO_EXTENSION) === 'php') {
                $this->files[] = $path;
            }
        }
    }

}


/**
 * Module 09: Parser
 * Trait containing parser-related methods for phpDocGenerator
 */

trait ParserModule
{
    private function findCommonBasePath()
    {
        $paths = [];
        foreach ($this->settings['directories'] as $dir) {
            $realPath = realpath($dir);
            if ($realPath) {
                $paths[] = $realPath;
            }
        }

        if (empty($paths)) {
            return '';
        }

        $commonPath = $paths[0];
        foreach ($paths as $path) {
            while (strpos($path, $commonPath) !== 0) {
                $commonPath = dirname($commonPath);
            }
        }

        return $commonPath;
    }

    private function parseFiles()
    {
        $this->output("🔍 Analyzing PHP files...");
        $total = count($this->files);
        $i = 0;
        $this->emitProgress('parsing', 0, $total, 'Analyzing PHP files');
        foreach ($this->files as $file) {
            $this->documentation[$file] = $this->parseFile($file);
            $i++;
            if ($this->shouldEmit($i, $total)) {
                $this->emitProgress('parsing', $i, $total, 'Analyzing PHP files');
            }
        }
        $this->emitProgress('parsing', $total, $total, 'Analyzing PHP files');
    }

    private function parseFile($file)
    {
        $content = file_get_contents($file);
        $tokens = token_get_all($content);

        $absoluteFile = realpath($file);

        // Relative path from generator.php for AJAX (works with open_basedir)
        $generatorDir = dirname(__FILE__);
        if (strpos($absoluteFile, $generatorDir) === 0) {
            $relativeFile = substr($absoluteFile, strlen($generatorDir) + 1);
        } else {
            // Fallback: use original relative path
            $relativeFile = $file;
        }

        // Create file ID for AJAX (bypasses WAF path traversal blocks)
        $fileId = md5($absoluteFile);
        $this->fileIndex[$fileId] = $absoluteFile;

        $doc = [
            'file' => $file,
            'classes' => [],
            'functions' => [],
            'constants' => []
        ];

        $currentClass = null;
        $currentComment = null;

        for ($i = 0; $i < count($tokens); $i++) {
            $token = $tokens[$i];

            if (is_array($token) && $token[0] === T_DOC_COMMENT) {
                $currentComment = $this->parseDocBlock($token[1]);
            }

            if (is_array($token) && $token[0] === T_CLASS) {
                // Skip ::class constant expressions (T_CLASS preceded by T_DOUBLE_COLON)
                $prevMeaningful = null;
                for ($j = $i - 1; $j >= 0; $j--) {
                    if (is_array($tokens[$j]) && $tokens[$j][0] === T_WHITESPACE) continue;
                    $prevMeaningful = $tokens[$j];
                    break;
                }
                if (is_array($prevMeaningful) && $prevMeaningful[0] === T_DOUBLE_COLON) {
                    continue;
                }

                $className = $this->getNextToken($tokens, $i, T_STRING);
                if ($className === '') { $currentComment = null; continue; } // anonymous class

                $doc['classes'][$className] = [
                    'name' => $className,
                    'comment' => $currentComment,
                    'methods' => [],
                    'properties' => []
                ];
                $currentClass = $className;
                $this->allClasses[] = ['name' => $className, 'file' => $file];
                $currentComment = null;
            }

            if (is_array($token) && $token[0] === T_FUNCTION) {
                $functionName = $this->getNextToken($tokens, $i, T_STRING);
                $params = $this->extractParameters($tokens, $i);

                // Track function position for source code viewer
                $lineStart = $token[2];
                $lineEnd = $this->findFunctionEnd($tokens, $i);

                $visibility = $currentClass ? $this->findVisibility($tokens, $i) : null;

                $functionData = [
                    'name' => $functionName,
                    'comment' => $currentComment,
                    'parameters' => $params,
                    'visibility' => $visibility,
                    'line_start' => $lineStart,
                    'line_end' => $lineEnd,
                    'file' => $relativeFile,
                    'file_id' => $fileId,
                ];

                if ($currentClass) {
                    $doc['classes'][$currentClass]['methods'][] = $functionData;
                } else {
                    $doc['functions'][] = $functionData;
                    $this->allFunctions[] = ['name' => $functionName, 'file' => $file];
                }
                $currentComment = null;
            }

            if (is_array($token) && $token[0] === T_CONST) {
                $constName = $this->getNextToken($tokens, $i, T_STRING);
                $doc['constants'][] = [
                    'name' => $constName,
                    'comment' => $currentComment
                ];
                $currentComment = null;
            }
        }

        return $doc;
    }

    private function parseDocBlock($comment)
    {
        $lines = explode("\n", $comment);
        $parsed = [
            'description' => '',
            'params' => [],
            'return' => '',
            'tags' => []
        ];

        $description = [];
        foreach ($lines as $line) {
            $line = trim($line, " \t\n\r\0\x0B*/");

            if (preg_match('/@param\s+(\S+)\s+\$(\S+)\s*(.*)/', $line, $matches)) {
                $parsed['params'][] = [
                    'type' => $matches[1],
                    'name' => $matches[2],
                    'description' => $matches[3] ?? ''
                ];
            } elseif (preg_match('/@return\s+(\S+)\s*(.*)/', $line, $matches)) {
                $parsed['return'] = $matches[1] . ' ' . ($matches[2] ?? '');
            } elseif (preg_match('/@(\w+)\s*(.*)/', $line, $matches)) {
                $parsed['tags'][$matches[1]] = $matches[2];
            } elseif (!empty($line)) {
                $description[] = $line;
            }
        }

        $parsed['description'] = implode(' ', $description);
        return $parsed;
    }

    private function getNextToken($tokens, $startIndex, $type)
    {
        for ($i = $startIndex + 1; $i < count($tokens); $i++) {
            if (is_array($tokens[$i]) && $tokens[$i][0] === $type) {
                return $tokens[$i][1];
            }
        }
        return '';
    }

    private function findVisibility($tokens, $functionIndex)
    {
        for ($i = $functionIndex - 1; $i >= 0; $i--) {
            $t = $tokens[$i];
            if (is_array($t)) {
                $type = $t[0];
                if ($type === T_PUBLIC) return 'public';
                if ($type === T_PROTECTED) return 'protected';
                if ($type === T_PRIVATE) return 'private';
                if ($type === T_DOC_COMMENT) break;
                if ($type === T_FUNCTION) break;
                if ($type === T_CLASS) break;
                if ($type === T_WHITESPACE) continue;
                if ($type === T_STATIC) continue;
                if ($type === T_ABSTRACT) continue;
                if ($type === T_FINAL) continue;
            } else {
                if ($t === '{' || $t === '}' || $t === ';') break;
            }
        }
        return 'public';
    }

    private function extractParameters($tokens, $startIndex)
    {
        $params = [];
        $inParams = false;
        $currentParam = '';

        for ($i = $startIndex; $i < count($tokens); $i++) {
            if ($tokens[$i] === '(') {
                $inParams = true;
                continue;
            }
            if ($tokens[$i] === ')') {
                if (!empty($currentParam)) {
                    $params[] = trim($currentParam);
                }
                break;
            }
            if ($inParams) {
                if ($tokens[$i] === ',') {
                    $params[] = trim($currentParam);
                    $currentParam = '';
                } else {
                    $currentParam .= is_array($tokens[$i]) ? $tokens[$i][1] : $tokens[$i];
                }
            }
        }

        return $params;
    }
}


/**
 * Module 10: TreeBuilder
 * Trait containing TreeBuilder-related methods for phpDocGenerator
 */

trait TreeBuilderModule
{
    private function buildFileTree() {
        $this->output("🌳 Building tree structure...");

        foreach ($this->files as $file) {
            $relativePath = $this->getRelativePath($file);

            if ($this->fileExistsInTree($relativePath)) {
                continue;
            }

            $parts = explode('/', $relativePath);

            $current = &$this->fileTree;
            foreach ($parts as $index => $part) {
                if ($index === count($parts) - 1) {
                    if (!isset($current['files'])) {
                        $current['files'] = [];
                    }
                    if (!in_array($part, $current['files'])) {
                        $current['files'][] = $part;
                    }
                } else {
                    if (!isset($current['dirs'][$part])) {
                        $current['dirs'][$part] = ['dirs' => [], 'files' => []];
                    }
                    $current = &$current['dirs'][$part];
                }
            }
        }
    }

    private function fileExistsInTree($relativePath) {
        $parts = explode('/', $relativePath);
        $current = $this->fileTree;

        foreach ($parts as $index => $part) {
            if ($index === count($parts) - 1) {
                return isset($current['files']) && in_array($part, $current['files']);
            } else {
                if (!isset($current['dirs'][$part])) {
                    return false;
                }
                $current = $current['dirs'][$part];
            }
        }

        return false;
    }

    private function getRelativePath($file) {
        $file = realpath($file);

        if ($this->baseDir && $file && strpos($file, $this->baseDir) === 0) {
            return str_replace('\\', '/', substr($file, strlen($this->baseDir) + 1));
        }

        return basename($file);
    }
}


/**
 * Module 11: OutputCreator
 * Trait containing OutputCreator-related methods for phpDocGenerator
 */

trait OutputCreatorModule
{
    private function createOutputStructure() {
        $this->output("📁 Creating directory structure...");

        if (!file_exists($this->settings['output_dir'])) {
            mkdir($this->settings['output_dir'], 0755, true);
        }

        $total = count($this->files);
        $i = 0;
        $this->emitProgress('structure', 0, $total, 'Creating directory structure');
        foreach ($this->files as $file) {
            $relativePath = $this->getRelativePath($file);
            $outputPath = $this->settings['output_dir'] . '/' . dirname($relativePath);

            if (!file_exists($outputPath)) {
                mkdir($outputPath, 0755, true);
            }
            $i++;
            if ($this->shouldEmit($i, $total)) {
                $this->emitProgress('structure', $i, $total, 'Creating directory structure');
            }
        }
        $this->emitProgress('structure', $total, $total, 'Creating directory structure');
    }

    private function generateHTMLFiles() {
        $this->output("📄 Generating HTML files...");

        $total = count($this->documentation);
        $i = 0;
        $this->emitProgress('html', 0, $total, 'Generating HTML files');
        foreach ($this->documentation as $file => $doc) {
            $relativePath = $this->getRelativePath($file);
            $displayPath  = $relativePath;
            // Change .php to _php in filename to avoid .htaccess blocking
            $relativePath = str_replace('.php', '_php', $relativePath);
            $outputFile = $this->settings['output_dir'] . '/' . $relativePath . '.html';

            $html = $this->generateFileHTML($file, $doc, $relativePath, $displayPath);
            file_put_contents($outputFile, $html);
            $i++;
            if ($this->shouldEmit($i, $total)) {
                $this->emitProgress('html', $i, $total, 'Generating HTML files');
            }
        }
        $this->emitProgress('html', $total, $total, 'Generating HTML files');
    }

    private function generateFileHTML($file, $doc, $relativePath, $displayPath = null) {
        $depth = substr_count($relativePath, '/');
        $rootPath = $depth > 0 ? str_repeat('../', $depth) : '';
        $generatorPath = str_repeat('../', $depth + 1) . 'generator.php';

        $breadcrumb = $this->generateBreadcrumb($relativePath, $rootPath);
        $content = $this->generateFileContent($file, $doc, $displayPath ?? $relativePath);

        return $this->getHTMLTemplate(
            basename($file),
            $breadcrumb . $content,
            'file',
            $rootPath,
            $generatorPath,
            $relativePath
        );
    }
}


/**
 * Module 12: HtmlGenerator
 * Trait containing HtmlGenerator-related methods for phpDocGenerator
 */

trait HtmlGeneratorModule
{
    private function generateBreadcrumb($path, $rootPath = '') {
        $parts = explode('/', $path);
        $breadcrumb = '<div class="breadcrumb">';
        $breadcrumb .= '<a href="' . $rootPath . 'index.html">' . $this->lang['GENERATOR_HOME'] . '</a>';

        $currentPath = '';
        foreach ($parts as $index => $part) {
            if ($index === count($parts) - 1) {
                $breadcrumb .= ' <span class="separator">›</span> <span class="current">' . htmlspecialchars($part) . '</span>';
            } else {
                $currentPath .= ($currentPath ? '/' : '') . $part;
                $breadcrumb .= ' <span class="separator">›</span> <a href="' . $rootPath . $currentPath . '/index.html">' . htmlspecialchars($part) . '</a>';
            }
        }

        $breadcrumb .= '</div>';
        return $breadcrumb;
    }

}


/**
 * Module 13: Components
 * Trait containing Components-related methods for phpDocGenerator
 */

trait ComponentsModule
{
    private function generateLanguagePicker()
    {
        $currentLang = $this->settings['language'];
        $currentLangData = $this->languages[$currentLang];

        $html = "<div class='language-picker'>\n";
        $html .= "<div class='lang-current' onclick='toggleLanguagePicker()'>\n";
        $html .= $currentLangData['flag'];
        $html .= "<span class='lang-name'>" . htmlspecialchars($currentLangData['native']) . "</span>\n";
        $html .= "<span class='lang-arrow'>▼</span>\n";
        $html .= "</div>\n";
        $html .= "<div class='lang-dropdown' id='langDropdown' style='display:none;'>\n";

        foreach ($this->settings['available_languages'] as $code) {
            if ($code === $currentLang) continue;
            if (!isset($this->languages[$code])) continue;

            $langData = $this->languages[$code];
            $html .= "<div class='lang-option' onclick='changeLang(\"$code\")'>\n";
            $html .= $langData['flag'];
            $html .= "<span class='lang-name'>" . htmlspecialchars($langData['native']) . "</span>\n";
            $html .= "</div>\n";
        }

        $html .= "</div>\n";
        $html .= "</div>\n";

        return $html;
    }

    private function generateTopBar($rootPath, $title, $currentRelativePath = '')
    {
        $version = self::VERSION;
        $homeHref = htmlspecialchars($rootPath . 'index.html');
        $picker = $this->generateLanguagePicker();

        $html = "<header class='topbar'>\n";
        $html .= "  <div class='topbar-logo'><a href='{$homeHref}' title='phpDG'>" . LOGO_SVG . "</a></div>\n";
        $html .= "  <div class='topbar-actions'>\n";
        $html .= "    <span class='pill pill-version'>v{$version}</span>\n";
        $html .= "    {$picker}\n";
        $html .= "    <div class='theme-switch' id='phpdg-theme-toggle' onclick='phpdgToggleTheme()' title='Toggle theme'><span class='ts-knob'></span><span class='ts-icon ts-sun'><svg width='12' height='12' viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round' stroke-linejoin='round'><circle cx='12' cy='12' r='5'/><line x1='12' y1='1' x2='12' y2='3'/><line x1='12' y1='21' x2='12' y2='23'/><line x1='4.22' y1='4.22' x2='5.64' y2='5.64'/><line x1='18.36' y1='18.36' x2='19.78' y2='19.78'/><line x1='1' y1='12' x2='3' y2='12'/><line x1='21' y1='12' x2='23' y2='12'/><line x1='4.22' y1='19.78' x2='5.64' y2='18.36'/><line x1='18.36' y1='5.64' x2='19.78' y2='4.22'/></svg></span><span class='ts-icon ts-moon'><svg width='12' height='12' viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round' stroke-linejoin='round'><path d='M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z'/></svg></span></div>\n";
        $html .= "  </div>\n";
        $html .= "</header>\n";
        return $html;
    }

    private function generateSidebarPanels($rootPath, $currentRelativePath)
    {
        $searchPh   = $this->lang['GENERATOR_SEARCH_PLACEHOLDER'] ?? 'Search...';
        $countFiles = count($this->files);
        $countClasses = count($this->allClasses);
        $countFn    = count($this->allFunctions);

        $fileTree = $this->generateSidebarFileTree($this->fileTree, '', $rootPath, $currentRelativePath);

        $html  = "<aside class='sidebar' id='sidebar'>\n";
        $html .= "  <div class='sidebar-search'>\n";
        $html .= "    <div class='sidebar-search-wrap'>\n";
        $html .= "      <svg class='sidebar-search-icon' viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round' stroke-linejoin='round'><circle cx='11' cy='11' r='8'/><path d='M21 21l-4.35-4.35'/></svg>\n";
        $html .= "      <input type='text' id='sidebarSearch' placeholder='" . htmlspecialchars($searchPh) . "'>\n";
        $html .= "    </div>\n";
        $html .= "  </div>\n";
        $html .= "  <div class='sidebar-search-results' id='sidebarSearchResults' style='display:none;'></div>\n";
        $html .= "  <div class='sidebar-tree' id='sidebarTree'>{$fileTree}</div>\n";
        $html .= "</aside>\n";
        return $html;
    }

    private function generateSidebarFileTree($tree, $path, $rootPath, $currentRelativePath, $forceExpandAll = false)
    {
        $html = "<div class='sb-tree'>\n";

        if (!empty($tree['dirs'])) {
            ksort($tree['dirs']);
            foreach ($tree['dirs'] as $dirName => $subTree) {
                $dirPath = $path === '' ? $dirName : $path . '/' . $dirName;
                $isAncestor = $currentRelativePath !== '' && (strpos($currentRelativePath, $dirPath . '/') === 0);
                $expanded = $forceExpandAll || $isAncestor;
                $expandedClass = $expanded ? ' expanded' : '';
                $childDisplay = $expanded ? 'block' : 'none';
                $count = count($subTree['files'] ?? []) + count($subTree['dirs'] ?? []);

                $html .= "<div class='sb-tree-dir{$expandedClass}' onclick='phpdgToggleSbDir(this, event)'>\n";
                $html .= "  <span class='sb-tree-chevron'><svg viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round' stroke-linejoin='round' width='12' height='12'><polyline points='9 18 15 12 9 6'/></svg></span>\n";
                $html .= "  <span class='sb-tree-dir-icon'><svg viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='1.6' stroke-linecap='round' stroke-linejoin='round' width='12' height='12'><path d='M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z'/></svg></span>\n";
                $html .= "  <span style='flex:1;'>" . htmlspecialchars($dirName) . "</span>\n";
                $html .= "  <span style='font-size:10px;color:#6b7280;'>{$count}</span>\n";
                $html .= "</div>\n";
                $html .= "<div class='sb-tree-children' style='display:{$childDisplay};'>\n";
                $html .= $this->generateSidebarFileTree($subTree, $dirPath, $rootPath, $currentRelativePath, $forceExpandAll);
                $html .= "</div>\n";
            }
        }

        if (!empty($tree['files'])) {
            sort($tree['files']);
            foreach ($tree['files'] as $fileName) {
                $relFilePath = $path === '' ? $fileName : $path . '/' . $fileName;
                $htmlFile = str_replace('.php', '_php', $relFilePath) . '.html';
                $href = $rootPath . htmlspecialchars($htmlFile);
                $isActive = ($relFilePath === $currentRelativePath);
                $activeClass = $isActive ? ' is-active' : '';
                $html .= "<a class='sb-tree-file{$activeClass}' href='{$href}'>\n";
                $html .= "  <span class='sb-tree-file-icon'><svg viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='1.6' stroke-linecap='round' stroke-linejoin='round' width='14' height='14'><path d='M13 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V9z'/><path d='M13 2v7h7'/></svg></span>\n";
                $html .= "  <span style='flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;'>" . htmlspecialchars($fileName) . "</span>\n";
                $html .= "</a>\n";
            }
        }

        $html .= "</div>\n";
        return $html;
    }

    private function generateStatusBar($title, $type)
    {
        $version = self::VERSION;
        $countFiles    = count($this->files);
        $countClasses  = count($this->allClasses);
        $countFn       = count($this->allFunctions);
        $statusLabel = $this->lang['GENERATOR_GENERATED'] ?? 'Generated';

        $html  = "<div class='statusbar'>\n";
        $html .= "  <div class='statusbar-left'>\n";
        $html .= "    <span>phpDG v{$version}</span>\n";
        if ($type !== 'main') {
            $html .= "    <span>" . htmlspecialchars($title) . "</span>\n";
        }
        $html .= "    <span class='pill'>{$countFiles} files</span>\n";
        $html .= "    <span class='pill'>{$countClasses} classes</span>\n";
        $html .= "    <span class='pill'>{$countFn} fn</span>\n";
        $html .= "  </div>\n";
        $html .= "  <div class='statusbar-right'>\n";
        $html .= "    <span class='status-dot'></span>\n";
        $html .= "    <span>" . htmlspecialchars($statusLabel) . "</span>\n";
        $html .= "  </div>\n";
        $html .= "</div>\n";
        return $html;
    }

    private function generateStatsCards()
    {
        $countFiles    = count($this->files);
        $countClasses  = count($this->allClasses);
        $countFn       = count($this->allFunctions);
        $filesLabel    = $this->lang['GENERATOR_FILES']     ?? 'Files';
        $classesLabel  = $this->lang['GENERATOR_CLASSES']   ?? 'Classes';
        $fnLabel       = $this->lang['GENERATOR_FUNCTIONS'] ?? 'Functions';

        $html  = "<div class='stats-row'>\n";
        $html .= "  <div class='stat-card'><span class='stat-number'>{$countFiles}</span><span class='stat-label' data-i18n='GENERATOR_FILES'>" . htmlspecialchars($filesLabel) . "</span></div>\n";
        $html .= "  <div class='stat-card'><span class='stat-number'>{$countClasses}</span><span class='stat-label' data-i18n='GENERATOR_CLASSES'>" . htmlspecialchars($classesLabel) . "</span></div>\n";
        $html .= "  <div class='stat-card'><span class='stat-number'>{$countFn}</span><span class='stat-label' data-i18n='GENERATOR_FUNCTIONS'>" . htmlspecialchars($fnLabel) . "</span></div>\n";
        $html .= "</div>\n";
        return $html;
    }
}


/**
 * Module 14: HtmlMethods
 * Trait containing HtmlMethods-related methods for phpDocGenerator
 */

trait HtmlMethodsModule
{
    private function generateFileContent($file, $doc, $relativePath = null) {
        $classCount    = count($doc['classes']);
        $methodCount   = 0;
        foreach ($doc['classes'] as $cls) { $methodCount += count($cls['methods']); }
        $functionCount = count($doc['functions']);

        $html  = "<div class='file-header'>\n";
        $html .= "  <div class='file-header-inner'>\n";
        $html .= "    <h1>" . $this->getFileIcon() . "<span>" . htmlspecialchars(basename($file)) . "</span></h1>\n";
        $displayPath = $relativePath ?? basename($file);
        $html .= "    <div class='file-path'>" . htmlspecialchars($displayPath) . "</div>\n";
        $html .= "    <div style='display:flex;gap:8px;margin-top:12px;flex-wrap:wrap;'>\n";
        if ($classCount > 0)    $html .= "      <span class='badge-vis public'>{$classCount} class</span>\n";
        if ($methodCount > 0)   $html .= "      <span class='badge-vis protected'>{$methodCount} methods</span>\n";
        if ($functionCount > 0) $html .= "      <span class='badge-vis private'>{$functionCount} fn</span>\n";
        $html .= "    </div>\n";
        $html .= "  </div>\n";
        $html .= "</div>\n";

        foreach ($doc['classes'] as $class) {
            $clsId = 'class-' . preg_replace('/[^a-zA-Z0-9_-]/', '', $class['name']);
            $html .= "<div class='class' id='" . htmlspecialchars($clsId) . "'>\n";
            $html .= "<h2><span class='keyword' data-i18n='GENERATOR_CLASS'>" . $this->lang['GENERATOR_CLASS'] . "</span> <span class='class-name'>" . htmlspecialchars($class['name']) . "</span></h2>\n";

            if ($class['comment'] && !empty($class['comment']['description'])) {
                $html .= "<div class='description'>" . htmlspecialchars($class['comment']['description']) . "</div>\n";
            }

            if (!empty($class['methods'])) {
                $html .= "<div class='methods-list'>\n";
                foreach ($class['methods'] as $index => $method) {
                    $html .= $this->generateMethodHTML($method, $index, $class['name']);
                }
                $html .= "</div>\n";
            }

            $html .= "</div>\n";
        }

        foreach ($doc['functions'] as $index => $function) {
            $html .= $this->generateFunctionHTML($function, $index);
        }

        return $html;
    }

    private function generateMethodHTML($method, $index, $className = '') {
        $id = 'method-' . preg_replace('/[^a-zA-Z0-9_-]/', '', $className) . '-' . $index;
        $params = !empty($method['parameters']) ? '(' . htmlspecialchars(implode(', ', $method['parameters'])) . ')' : '()';
        $vis = $method['visibility'] ?? 'public';
        $visClass = in_array($vis, ['public', 'protected', 'private'], true) ? $vis : 'public';

        $html  = "<div class='method-item'>\n";
        $html .= "  <div class='method-header' onclick='toggleMethod(\"$id\")'>\n";
        $html .= "    <span class='vis-dot vis-{$visClass}' aria-label='{$visClass}'></span>\n";
        $html .= "    <span class='function-name'>" . htmlspecialchars($method['name']) . "</span>\n";
        $html .= "    <span class='params-preview'>" . $params . "</span>\n";
        $html .= "    <span class='method-meta'><span class='badge-vis {$visClass}'>{$visClass}</span><span class='toggle-icon' id='icon-{$id}'><svg viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='2.5' stroke-linecap='round' stroke-linejoin='round' width='12' height='12'><polyline points='9 18 15 12 9 6'/></svg></span></span>\n";
        $html .= "  </div>\n";

        $html .= "  <div class='method-details' id='{$id}' style='display:none;'>\n";

        if ($method['comment'] && !empty($method['comment']['description'])) {
            $html .= "<div class='description'>" . htmlspecialchars($method['comment']['description']) . "</div>\n";
        }

        if ($method['comment'] && !empty($method['comment']['params'])) {
            $html .= "<div class='parameters'><strong data-i18n='GENERATOR_PARAMETERS'>" . $this->lang['GENERATOR_PARAMETERS'] . "</strong>\n";
            foreach ($method['comment']['params'] as $param) {
                $html .= "<div class='param'><span class='type'>" . htmlspecialchars($param['type']) . "</span> ";
                $html .= "<span class='var'>\$" . htmlspecialchars($param['name']) . "</span>";
                if (!empty($param['description'])) {
                    $html .= " <span class='param-desc'>— " . htmlspecialchars($param['description']) . "</span>";
                }
                $html .= "</div>\n";
            }
            $html .= "</div>\n";
        }

        if ($method['comment'] && !empty($method['comment']['return'])) {
            $html .= "<div class='return'><span class='keyword' data-i18n='GENERATOR_RETURN'>" . $this->lang['GENERATOR_RETURN'] . "</span> " . htmlspecialchars($method['comment']['return']) . "</div>\n";
        }

        if (isset($method['line_start']) && isset($method['line_end']) && isset($method['file_id'])) {
            $fid  = htmlspecialchars($method['file_id']);
            $ls   = $method['line_start']; $le = $method['line_end'];
            $name = htmlspecialchars($method['name']);
            $html .= "<div class='source-view-button'>\n";
            $html .= "<button class='btn-view-source' onclick='viewSource(\"{$fid}\",{$ls},{$le},\"{$name}\")'><span data-i18n='GENERATOR_VIEW_SOURCE'>" . $this->lang['GENERATOR_VIEW_SOURCE'] . "</span></button>\n";
            $html .= "<button class='btn-copy-source' onclick='copySource(\"{$fid}\",{$ls},{$le},this)' title='Copy source'><svg viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round' stroke-linejoin='round' width='13' height='13'><rect x='9' y='9' width='13' height='13' rx='2'/><path d='M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1'/></svg> Copy</button>\n";
            $html .= "</div>\n";
        }

        $html .= "  </div>\n";
        $html .= "</div>\n";
        return $html;
    }

    private function generateFunctionHTML($function, $index) {
        $id = 'func-' . $index;
        $params = !empty($function['parameters']) ? '(' . htmlspecialchars(implode(', ', $function['parameters'])) . ')' : '()';

        $html  = "<div class='function'>\n";
        $html .= "  <div class='method-header' onclick='toggleMethod(\"$id\")'>\n";
        $html .= "    <span class='vis-dot' style='background:#0ea5e9;box-shadow:0 0 0 3px rgba(14,165,233,0.18);'></span>\n";
