        $html .= "    <span class='params-preview'>" . $params . "</span>\n";
        $html .= "    <span class='method-meta'><span class='badge-vis' style='background:rgba(14,165,233,0.15);color:#0ea5e9;'>function</span><span class='toggle-icon' id='icon-{$id}'><svg viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='2.5' stroke-linecap='round' stroke-linejoin='round' width='12' height='12'><polyline points='9 18 15 12 9 6'/></svg></span></span>\n";
        $html .= "  </div>\n";

        $html .= "  <div class='method-details' id='{$id}' style='display:none;'>\n";

        if ($function['comment'] && !empty($function['comment']['description'])) {
            $html .= "<div class='description'>" . htmlspecialchars($function['comment']['description']) . "</div>\n";
        }

        if ($function['comment'] && !empty($function['comment']['params'])) {
            $html .= "<div class='parameters'><strong data-i18n='GENERATOR_PARAMETERS'>" . $this->lang['GENERATOR_PARAMETERS'] . "</strong>\n";
            foreach ($function['comment']['params'] as $param) {
                $html .= "<div class='param'><span class='type'>" . htmlspecialchars($param['type']) . "</span> ";
                $html .= "<span class='var'>\$" . htmlspecialchars($param['name']) . "</span>";
                if (!empty($param['description'])) {
                    $html .= " <span class='param-desc'>— " . htmlspecialchars($param['description']) . "</span>";
                }
                $html .= "</div>\n";
            }
            $html .= "</div>\n";
        }

        if ($function['comment'] && !empty($function['comment']['return'])) {
            $html .= "<div class='return'><span class='keyword' data-i18n='GENERATOR_RETURN'>" . $this->lang['GENERATOR_RETURN'] . "</span> " . htmlspecialchars($function['comment']['return']) . "</div>\n";
        }

        if (isset($function['line_start']) && isset($function['line_end']) && isset($function['file_id'])) {
            $fid  = htmlspecialchars($function['file_id']);
            $ls   = $function['line_start']; $le = $function['line_end'];
            $name = htmlspecialchars($function['name']);
            $html .= "<div class='source-view-button'>\n";
            $html .= "<button class='btn-view-source' onclick='viewSource(\"{$fid}\",{$ls},{$le},\"{$name}\")'><span data-i18n='GENERATOR_VIEW_SOURCE'>" . $this->lang['GENERATOR_VIEW_SOURCE'] . "</span></button>\n";
            $html .= "<button class='btn-copy-source' onclick='copySource(\"{$fid}\",{$ls},{$le},this)' title='Copy source'><svg viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='2' stroke-linecap='round' stroke-linejoin='round' width='13' height='13'><rect x='9' y='9' width='13' height='13' rx='2'/><path d='M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1'/></svg> Copy</button>\n";
            $html .= "</div>\n";
        }

        $html .= "  </div>\n";
        $html .= "</div>\n";
        return $html;
    }
}


/**
* Module 15: DirectoryIndexes
* Trait containing DirectoryIndexes-related methods for phpDocGenerator
*/

trait DirectoryIndexesModule
{
private function generateDirectoryIndexes() {
$this->output("📂 Generating directory indexes...");
$this->generateDirIndex($this->fileTree, '');
}

private function generateDirIndex($tree, $path) {
if (!empty($tree['dirs'])) {
foreach ($tree['dirs'] as $dirName => $subTree) {
$dirPath = $path ? $path . '/' . $dirName : $dirName;
$outputFile = $this->settings['output_dir'] . '/' . $dirPath . '/index.html';

$depth = substr_count($dirPath, '/') + 1;
$rootPath = str_repeat('../', $depth);

$breadcrumb = $this->generateBreadcrumb($dirPath, $rootPath);
$treeHtml = $this->generateTreeHTML($subTree);
$content = $breadcrumb . "<div class='directory-index'><h1>" . $this->getFolderIcon() . " " . htmlspecialchars($dirName) . "</h1>" . $treeHtml . "</div>";

$html = $this->getHTMLTemplate($dirName, $content, 'directory', $rootPath, $rootPath . '../generator.php', $dirPath);
file_put_contents($outputFile, $html);

$this->generateDirIndex($subTree, $dirPath);
}
}
}

private function generateTreeHTML($tree) {
$html = "<div class='tree'>\n";

    if (!empty($tree['dirs'])) {
    ksort($tree['dirs']);
    foreach ($tree['dirs'] as $dirName => $subTree) {
    $html .= "<div class='tree-item'>\n";
        $html .= $this->getFolderIcon() . " <a href='" . htmlspecialchars($dirName) . "/index.html'>" . htmlspecialchars($dirName) . "</a>\n";
        $html .= "</div>\n";
    }
    }

    if (!empty($tree['files'])) {
    sort($tree['files']);
    foreach ($tree['files'] as $fileName) {
    $html .= "<div class='tree-item'>\n";
        $fileNameHtml = str_replace('.php', '_php', $fileName);
        $html .= $this->getFileIcon() . " <a href='" . htmlspecialchars($fileNameHtml) . ".html'>" . htmlspecialchars($fileName) . "</a>\n";
        $html .= "</div>\n";
    }
    }

    $html .= "</div>\n";
return $html;
}

private function generateMainIndex() {
$this->output("🏠 Generating main index.html...");

$content = $this->generateStatsCards();

// Classes section
if (!empty($this->allClasses)) {
    $label = $this->lang['GENERATOR_CLASSES_HEADING'] ?? 'Classes';
    $sorted = $this->allClasses;
    usort($sorted, fn($a, $b) => strcmp($a['name'], $b['name']));

    $count = count($sorted);
    $content .= "<section class='index-section'>\n";
    $content .= "<h2 class='index-section-title' onclick='phpdgToggleIndex(this)'>";
    $content .= "<span class='index-chevron'><svg viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='2.5' stroke-linecap='round' stroke-linejoin='round' width='13' height='13'><polyline points='9 18 15 12 9 6'/></svg></span>";
    $content .= htmlspecialchars($label);
    $content .= "<span class='index-count'>{$count}</span>";
    $content .= "</h2>\n";
    $content .= "<div class='index-table' style='display:none;'>\n";
    foreach ($sorted as $cls) {
        $relPath  = $this->getRelativePath($cls['file']);
        $htmlPath = str_replace('.php', '_php', $relPath) . '.html';
        $anchor   = '#class-' . preg_replace('/[^a-zA-Z0-9_-]/', '', $cls['name']);
        $dir      = dirname($relPath) !== '.' ? dirname($relPath) . '/' : '';
        $base     = basename($relPath);
        $content .= "<a class='index-row' href='" . htmlspecialchars($htmlPath . $anchor) . "'>";
        $content .= "<span class='index-symbol'>" . htmlspecialchars($cls['name']) . "</span>";
        $content .= "<span class='index-file'><span class='index-file-dir'>" . htmlspecialchars($dir) . "</span>" . htmlspecialchars($base) . "</span>";
        $content .= "</a>\n";
    }
    $content .= "</div>\n</section>\n";
}

// Functions section
if (!empty($this->allFunctions)) {
    $label = $this->lang['GENERATOR_FUNCTIONS_HEADING'] ?? 'Functions';
    $sorted = $this->allFunctions;
    usort($sorted, fn($a, $b) => strcmp($a['name'], $b['name']));

    $count = count($sorted);
    $content .= "<section class='index-section'>\n";
    $content .= "<h2 class='index-section-title' onclick='phpdgToggleIndex(this)'>";
    $content .= "<span class='index-chevron'><svg viewBox='0 0 24 24' fill='none' stroke='currentColor' stroke-width='2.5' stroke-linecap='round' stroke-linejoin='round' width='13' height='13'><polyline points='9 18 15 12 9 6'/></svg></span>";
    $content .= htmlspecialchars($label);
    $content .= "<span class='index-count'>{$count}</span>";
    $content .= "</h2>\n";
    $content .= "<div class='index-table' style='display:none;'>\n";
    foreach ($sorted as $fn) {
        $relPath  = $this->getRelativePath($fn['file']);
        $htmlPath = str_replace('.php', '_php', $relPath) . '.html';
        $dir      = dirname($relPath) !== '.' ? dirname($relPath) . '/' : '';
        $base     = basename($relPath);
        $content .= "<a class='index-row' href='" . htmlspecialchars($htmlPath) . "'>";
        $content .= "<span class='index-symbol'>" . htmlspecialchars($fn['name']) . "</span>";
        $content .= "<span class='index-file'><span class='index-file-dir'>" . htmlspecialchars($dir) . "</span>" . htmlspecialchars($base) . "</span>";
        $content .= "</a>\n";
    }
    $content .= "</div>\n</section>\n";
}

$html = $this->getHTMLTemplate('phpDG', $content, 'main', '', '../generator.php', '');
file_put_contents($this->settings['output_dir'] . '/index.html', $html);
}

private function getFolderIcon() {
return '<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" class="icon"><path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/></svg>';
}

private function getFileIcon() {
return '<svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" class="icon"><path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/><polyline points="14 2 14 8 20 8"/><path d="M10 13l-2 2 2 2"/><path d="M14 13l2 2-2 2"/></svg>';
}

}


/* ========= MERGE POINT: JSON INDEX ========= */

class phpDocGenerator {
    const VERSION = PHPDG_VERSION;

    // ════════════════════════════════════════════════════════════════════════════
    // PROPERTIES
    // ════════════════════════════════════════════════════════════════════════════

    private $settings = [];
    private $files = [];
    private $documentation = [];
    private $allClasses = [];
    private $allFunctions = [];
    private $fileTree = [];
    private $baseDir = null;
    private $lang = [];
    private $languages = [];
    private $translations = [];
    private $isCLI = false;
    private $fileIndex = [];  // File ID index for AJAX source viewer
    public $sseMode = false;  // Stream progress as SSE events

    // ════════════════════════════════════════════════════════════════════════════
    // TRAITS - Module methods
    // ════════════════════════════════════════════════════════════════════════════

    use ScannerModule;              // 08: scanDirectories(), scanDirectory(), findCommonBasePath()
    use ParserModule;               // 09: parseFiles(), parseFile(), parseDocBlock()
    use TreeBuilderModule;          // 10: buildFileTree(), fileExistsInTree()
    use OutputCreatorModule;        // 11: createOutputStructure(), generateHTMLFiles()
    use HtmlGeneratorModule;        // 12: generateFileHTML(), generateBreadcrumb()
    use ComponentsModule;           // 13: generateHeader(), generateLanguagePicker()
    use HtmlMethodsModule;          // 14: generateMethodHTML(), generateFunctionHTML()
    use DirectoryIndexesModule;     // 15: generateDirectoryIndexes(), generateMainIndex()
    use JsonIndexModule;            // 18: generateJsonIndex()

    // ════════════════════════════════════════════════════════════════════════════
    // CONSTRUCTOR
    // ════════════════════════════════════════════════════════════════════════════

    public function __construct($settings, $translations, $languages) {
        $this->settings = $settings;
        $this->translations = $translations;
        $this->languages = $languages;
        $this->lang = $translations[$settings['language']] ?? $translations['en'];
        $this->isCLI = php_sapi_name() === 'cli';
        $this->validateSettings();
    }

    /**
     * Output message with proper line break based on environment
     */
    private function output($message) {
        if ($this->sseMode) return;
        if ($this->isCLI) {
            echo $message . "\n";
        } else {
            echo htmlspecialchars($message) . "<br>\n";
        }
    }

    public function emitProgress($step, $current, $total, $label = '') {
        if (!$this->sseMode) return;
        $pct = $total > 0 ? (int)round($current * 100 / $total) : 0;
        $payload = json_encode([
            'step' => $step,
            'current' => $current,
            'total' => $total,
            'label' => $label,
            'pct' => $pct,
        ], JSON_UNESCAPED_UNICODE);
        echo "event: progress\ndata: {$payload}\n\n";
        @ob_flush();
        @flush();
    }

    private function shouldEmit($current, $total) {
        if (!$this->sseMode) return false;
        if ($current === 0 || $current === $total) return true;
        $interval = max(1, (int)($total / 100));
        return ($current % $interval) === 0;
    }

    private function validateSettings() {
        if (empty($this->settings['directories'])) {
            $this->output("❌ Missing 'directories' in settings!");
            exit(1);
        }
        if (empty($this->settings['output_dir'])) {
            $this->settings['output_dir'] = 'output';
        }
    }

    public function generate() {
        $this->output("🚀 Starting phpDocGenerator v" . self::VERSION . "...");
        $this->output("");

        $this->emitProgress('scan', 0, 1, 'Scanning directories');
        $this->scanDirectories();
        $this->emitProgress('scan', 1, 1, 'Scanning directories');

        $this->baseDir = $this->findCommonBasePath();
        $this->parseFiles();
        $this->buildFileTree();
        $this->createOutputStructure();
        $this->generateHTMLFiles();

        $this->emitProgress('dir-index', 0, 1, 'Generating directory indexes');
        $this->generateDirectoryIndexes();
        $this->emitProgress('dir-index', 1, 1, 'Generating directory indexes');

        $this->emitProgress('main-index', 0, 1, 'Generating main index.html');
        $this->generateMainIndex();
        $this->emitProgress('main-index', 1, 1, 'Generating main index.html');

        $this->emitProgress('htaccess', 0, 1, 'Creating .htaccess');
        $this->createHtaccess();
        $this->emitProgress('htaccess', 1, 1, 'Creating .htaccess');

        $this->emitProgress('json-index', 0, 1, 'Generating JSON file index');
        $this->generateJsonIndex();
        $this->emitProgress('json-index', 1, 1, 'Generating JSON file index');

        $this->output("");
        $this->output("✅ Done! Open {$this->settings['output_dir']}/index.html in your browser.");
    }

    private function createHtaccess() {
        $this->output("🔐 Creating .htaccess...");

        $htaccess = '';

        if (!empty($this->settings['http_auth'])) {
            $htpasswdContent = '';
            foreach ($this->settings['http_auth'] as $username => $password) {
                $htpasswdContent .= $username . ':' . crypt($password, base64_encode($password)) . "\n";
            }
            file_put_contents($this->settings['output_dir'] . '/.htpasswd', trim($htpasswdContent));

            $htpasswdPath = realpath($this->settings['output_dir'] . '/.htpasswd');

            $htaccess = <<<HTACCESS
# HTTP Authentication
AuthType Basic
AuthName "phpDocGenerator - {$this->lang['GENERATOR_PROTECTED_AREA']}"
AuthUserFile {$htpasswdPath}
Require valid-user

# Allow HTML and assets for authenticated users
<FilesMatch "\\.(html|css|js|png|jpg|gif|svg)$">
    Satisfy Any
</FilesMatch>


HTACCESS;
            $this->output("   ✓ {$this->lang['GENERATOR_AUTH_ENABLED']}");
            $this->output("   {$this->lang['GENERATOR_USERS']}:");
            foreach ($this->settings['http_auth'] as $username => $password) {
                $this->output("     - {$username}");
            }
        } else {
            $this->output("   ⚠   {$this->lang['GENERATOR_AUTH_DISABLED']}");
        }

        $htaccess .= <<<HTACCESS
# Block access to PHP files
<FilesMatch "\\.php$">
    Order Allow,Deny
    Deny from all
</FilesMatch>

# Allow access to HTML and assets
<FilesMatch "\\.(html|css|js|png|jpg|gif|svg)$">
    Order Allow,Deny
    Allow from all
</FilesMatch>

# Index files
DirectoryIndex index.html
HTACCESS;

        file_put_contents($this->settings['output_dir'] . '/.htaccess', $htaccess);
    }

    private function getHTMLTemplate($title, $content, $type, $rootPath = '', $generatorPath = 'generator.php', $currentRelativePath = '') {
        // Get translations as JSON for JavaScript
        $translationsJson = json_encode($this->translations, JSON_UNESCAPED_UNICODE);
        $languagesJson = json_encode($this->languages, JSON_UNESCAPED_UNICODE);
        $availableLanguagesJson = json_encode($this->settings['available_languages'], JSON_UNESCAPED_UNICODE);

        // Get direction from current language
        $direction = $this->languages[$this->settings['language']]['direction'] ?? 'ltr';

        $topBar = $this->generateTopBar($rootPath, $title, $currentRelativePath);
        $sidebar = $this->generateSidebarPanels($rootPath, $currentRelativePath);
        $statusBar = $this->generateStatusBar($title, $type);
        $searchIndexJson = $this->buildSearchIndexJson($rootPath);

        return <<<HTML
<!DOCTYPE html>
<html lang="{$this->settings['language']}" dir="{$direction}" data-theme="dark">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>PHPDG</title>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Sofia+Sans:wght@400;500;600;700&display=swap" rel="stylesheet">
    <style>
    /* ============================================================================
   phpDG — design system v0.6
   ============================================================================
   Tokens
   - Background:     #0f1117 (base) / #16181f (card) / #090b10 (deep/status)
   - Border:         var(--border) / 0.12 hover
   - Accent:         #4f46e5 (indigo)  + #7c3aed (purple, gradient pair)
   - Text:           #f9fafb / #e5e7eb / #9ca3af / #6b7280 / #4b5563 / #374151
   - Visibility:     public #10b981 · protected #f59e0b · private #ef4444
   - Type:           teal #4ec9b0 · keyword #c586c0 · param #ce9178 · var #9cdcfe
   - Fonts:          Sofia Sans (UI) / system monospace (code)
   - Shell:          topbar 48 · sidebar 260 · statusbar 24
   ============================================================================ */


