.topbar-actions {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 0 16px;
    flex-shrink: 0;
    margin-left: auto;
}
.pill {
    font-size: 10px;
    padding: 3px 10px;
    border-radius: 20px;
    background: var(--hover);
    color: var(--text-muted);
    font-family: Consolas, Menlo, Monaco, monospace;
    white-space: nowrap;
}
.pill-version { color: var(--text-dim); }

/* ── Sidebar ──────────────────────────────────────────────────────── */
.sidebar {
    width: 260px;
    flex-shrink: 0;
    background: var(--surface);
    border-right: 1px solid var(--border);
    display: flex;
    flex-direction: column;
    overflow: hidden;
}
.sidebar-tree {
    flex: 1;
    overflow-y: auto;
    padding: 6px 8px 12px;
}
.sidebar-search-results {
    flex: 1;
    overflow-y: auto;
    padding: 6px 10px 12px;
}

/* ── Sidebar tree items ───────────────────────────────────────────── */
.sb-tree-dir, .sb-tree-file {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 7px 8px;
    border-radius: 6px;
    color: var(--text-mid);
    text-decoration: none;
    font-size: 13px;
    cursor: pointer;
    user-select: none;
    transition: background 0.1s;
}
.sb-tree-dir:hover, .sb-tree-file:hover { background: var(--hover); }
.sb-tree-file { padding-left: 28px; color: var(--text-mid); }
.sb-tree-file:hover { color: var(--text-mid); }
.sb-tree-file.is-active {
    background: rgba(79,70,229,0.16);
    color: #fff;
}
.sb-tree-dir-icon { color: #f59e0b; display: flex; flex-shrink: 0; }
[data-theme="light"] .sb-tree-dir-icon { color: #cc5500; }
.sb-tree-file-icon { color: #4f46e5; display: flex; flex-shrink: 0; }
.sb-tree-chevron {
    width: 12px;
    color: var(--text-muted);
    transition: transform 0.2s;
    display: flex;
    flex-shrink: 0;
}
.sb-tree-dir.expanded .sb-tree-chevron { transform: rotate(90deg); }
.sb-tree-children {
    margin-left: 12px;
    padding-left: 4px;
    border-left: 1px solid var(--border3);
    display: none;
}
.sb-tree-dir.expanded + .sb-tree-children { display: block; }

/* sidebar search */
.sidebar-search {
    padding: 10px 12px;
    border-bottom: 1px solid var(--border);
    flex-shrink: 0;
}
.sidebar-search-wrap {
    position: relative;
    display: flex;
    align-items: center;
}
.sidebar-search-icon {
    position: absolute;
    left: 9px;
    width: 14px;
    height: 14px;
    color: var(--text-muted);
    pointer-events: none;
    flex-shrink: 0;
}
.sidebar-search input {
    width: 100%;
    background: var(--input-bg);
    border: 1px solid var(--input-bdr);
    color: var(--text);
    border-radius: 8px;
    padding: 8px 10px 8px 30px;
    font-size: 13px;
    font-family: inherit;
    outline: none;
}
.sidebar-search input:focus { border-color: #4f46e5; background: var(--border); }
.sidebar-search input::placeholder { color: var(--text-dim); }

.sidebar-search-results { padding: 6px 10px; }
.sidebar-search-results .sb-result {
    padding: 6px 8px;
    border-radius: 6px;
    color: var(--text-mid);
    font-size: 12.5px;
    cursor: pointer;
    text-decoration: none;
    display: block;
}
.sidebar-search-results .sb-result:hover { background: var(--border3); }
.sidebar-empty {
    padding: 40px 14px;
    text-align: center;
    color: var(--text-dim);
    font-size: 12px;
}

/* ── Main content ─────────────────────────────────────────────────── */
.main {
    flex: 1;
    overflow-y: auto;
    background: var(--bg);
    position: relative;
}
.main::before {
    content: "";
    position: absolute;
    inset: 0;
    pointer-events: none;
    background-image: radial-gradient(circle, var(--dot) 1px, transparent 1px);
    background-size: 28px 28px;
    z-index: 0;
}
.container {
    position: relative;
    z-index: 1;
    max-width: 1100px;
    margin: 0 auto;
    padding: 22px 28px 32px;
}

/* ── Breadcrumb ───────────────────────────────────────────────────── */
.breadcrumb {
    display: flex;
    align-items: center;
    flex-wrap: wrap;
    gap: 6px;
    margin-bottom: 18px;
    font-size: 12px;
    color: var(--text-muted);
    font-family: Consolas, Menlo, Monaco, monospace;
}
.breadcrumb a { color: #4f46e5; text-decoration: none; }
.breadcrumb a:hover { color: #6366f1; text-decoration: underline; }
.breadcrumb .separator { color: var(--text-sep); }
.breadcrumb .current { color: var(--text-mid); }

/* ── File / class card ────────────────────────────────────────────── */
.file-header {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 14px;
    overflow: hidden;
    margin-bottom: 18px;
    box-shadow: 0 12px 36px rgba(0,0,0,0.25);
}
.file-header::before {
    content: "";
    display: block;
    height: 3px;
    background: linear-gradient(90deg, #4f46e5, #7c3aed);
}
.file-header-inner {
    padding: 18px 22px 18px;
}
.file-header h1 {
    font-size: 20px;
    font-weight: 700;
    color: var(--text-hi);
    letter-spacing: -0.02em;
    margin: 0;
    display: flex;
    align-items: center;
    gap: 10px;
}
.file-header .icon { color: #4f46e5; display: inline-flex; vertical-align: middle; }
.file-path {
    color: var(--text-muted);
    font-size: 12px;
    margin-top: 4px;
    font-family: Consolas, Menlo, Monaco, monospace;
}

/* ── Class card ───────────────────────────────────────────────────── */
.class {
    background: var(--surface);
    border: 1px solid var(--border);
    border-left: 3px solid #4f46e5;
    border-radius: 12px;
    padding: 16px 20px 18px;
    margin: 18px 0;
}
.class h2 {
    font-size: 16px;
    font-weight: 700;
    color: var(--text-hi);
    letter-spacing: -0.01em;
    margin-bottom: 10px;
    display: flex;
    align-items: center;
    gap: 8px;
}
.class .keyword {
    font-size: 10px;
    font-weight: 700;
    padding: 2px 8px;
    border-radius: 20px;
    background: rgba(197,134,192,0.15);
    color: #c586c0;
    letter-spacing: 0.05em;
    text-transform: lowercase;
}
.class-name { color: #4ec9b0; font-family: Consolas, Menlo, Monaco, monospace; font-weight: 600; }

h3 {
    color: #dcdcaa;
    font-size: 14px;
    font-weight: 600;
    margin: 16px 0 8px;
    letter-spacing: -0.01em;
}

/* ── Methods / functions ──────────────────────────────────────────── */
.methods-list { margin-top: 12px; display: flex; flex-direction: column; gap: 6px; }
.method-item, .function {
    background: var(--surface2);
    border: 1px solid var(--border2);
    border-radius: 10px;
    overflow: hidden;
    transition: border-color 0.15s;
}
.method-item:hover, .function:hover { border-color: var(--input-bdr); }
.method-item.is-open, .function.is-open { border-color: rgba(79,70,229,0.4); }

.method-header {
    padding: 10px 14px;
    cursor: pointer;
    user-select: none;
    display: flex;
    align-items: center;
    gap: 10px;
    font-family: 'Sofia Sans', sans-serif;
}
.method-header:hover { background: var(--hover2); }
.vis-dot {
    width: 7px;
    height: 7px;
    border-radius: 50%;
    background: #6b7280;
    flex-shrink: 0;
}
.vis-public    { background: #10b981; box-shadow: 0 0 0 3px rgba(16,185,129,0.18); }
.vis-protected { background: #f59e0b; box-shadow: 0 0 0 3px rgba(245,158,11,0.18); }
.vis-private   { background: #ef4444; box-shadow: 0 0 0 3px rgba(239,68,68,0.18); }
.method-meta {
    display: flex;
    align-items: center;
    gap: 8px;
    margin-left: auto;
    flex-shrink: 0;
}
.toggle-icon {
    color: var(--text-dim);
    width: 14px;
    height: 14px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: transform 0.2s, color 0.15s;
    flex-shrink: 0;
}
.toggle-icon svg { display: block; }
.toggle-icon.expanded { transform: rotate(90deg); color: #4f46e5; }

.function-name {
    color: var(--text-mid);
    font-family: Consolas, Menlo, Monaco, monospace;
    font-weight: 600;
    font-size: 13px;
}
.params-preview {
    color: var(--text-dim);
    font-family: Consolas, Menlo, Monaco, monospace;
    font-size: 11.5px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
    max-width: 380px;
    flex: 1;
    min-width: 0;
}
.method-header .keyword {
    font-size: 9.5px;
    font-weight: 700;
    padding: 2px 7px;
    border-radius: 20px;
    background: rgba(197,134,192,0.13);
    color: #c586c0;
    letter-spacing: 0.06em;
    text-transform: uppercase;
}
.badge-vis {
    font-size: 9.5px;
    font-weight: 700;
    padding: 2px 0;
    border-radius: 20px;
    letter-spacing: 0.04em;
    flex-shrink: 0;
    min-width: 72px;
    text-align: center;
}
.badge-vis.public    { background: rgba(16,185,129,0.15);  color: #10b981; }
.badge-vis.protected { background: rgba(245,158,11,0.15);  color: #f59e0b; }
.badge-vis.private   { background: rgba(239,68,68,0.15);   color: #ef4444; }
[data-theme="light"] .badge-vis.public    { color: #0a6640; }
[data-theme="light"] .badge-vis.protected { color: #cc5500; }
[data-theme="light"] .badge-vis.private   { color: #b91c1c; }

.method-details {
    padding: 0 14px 14px 30px;
    border-top: 1px solid var(--border2);
}
.description {
    color: var(--text);
    margin: 12px 0;
    padding: 10px 12px;
    background: var(--subtle);
    border-left: 2px solid #4f46e5;
    border-radius: 6px;
    font-size: 13px;
    line-height: 1.6;
}
.parameters { margin: 12px 0; }
.parameters > strong {
    display: block;
    font-size: 11px;
    font-weight: 700;
    color: var(--text-muted);
    text-transform: uppercase;
    letter-spacing: 0.06em;
    margin-bottom: 6px;
}
.param {
    background: var(--subtle);
    padding: 7px 11px;
    margin: 4px 0;
    border-left: 2px solid #ce9178;
    border-radius: 4px;
    font-family: Consolas, Menlo, Monaco, monospace;
    font-size: 12px;
}
.type { color: #4ec9b0; }
.var { color: #9cdcfe; }
.param-desc { color: var(--text-muted); font-family: 'Sofia Sans', sans-serif; }
.return {
    margin: 12px 0 6px;
    padding: 8px 12px;
    background: var(--subtle);
    border-left: 2px solid #c586c0;
    border-radius: 4px;
    font-size: 12px;
    color: var(--text);
    font-family: Consolas, Menlo, Monaco, monospace;
}
.return .keyword {
    color: #c586c0;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    font-size: 10px;
    margin-right: 6px;
}

/* ── View source button ───────────────────────────────────────────── */
.source-view-button {
    margin-top: 12px;
    padding-top: 12px;
    border-top: 1px solid var(--border2);
    display: flex;
    gap: 8px;
    flex-wrap: wrap;
}
.btn-view-source {
    background: rgba(79,70,229,0.15);
    color: #a5b4fc;
    border: 1px solid rgba(79,70,229,0.3);
    padding: 6px 12px;
    border-radius: 7px;
    cursor: pointer;
    font-size: 12px;
    font-weight: 500;
    font-family: 'Sofia Sans', sans-serif;
    display: inline-flex;
    align-items: center;
    gap: 6px;
    transition: background 0.15s, border-color 0.15s;
}
.btn-view-source:hover { background: rgba(79,70,229,0.25); border-color: rgba(79,70,229,0.5); }
[data-theme="light"] .btn-view-source { color: #4338ca; border-color: rgba(79,70,229,0.45); }
[data-theme="light"] .btn-view-source:hover { background: rgba(79,70,229,0.2); border-color: rgba(79,70,229,0.65); }
.btn-view-source::before {
    content: "</>";
    font-family: Consolas, Menlo, Monaco, monospace;
    font-size: 11px;
    opacity: 0.7;
}
.btn-copy-source {
    background: var(--border3);
    color: #9ca3af;
    border: 1px solid rgba(255,255,255,0.1);
    padding: 6px 12px;
    border-radius: 7px;
    cursor: pointer;
    font-size: 12px;
    font-weight: 500;
    font-family: 'Sofia Sans', sans-serif;
    display: inline-flex;
    align-items: center;
    gap: 6px;
    transition: background 0.15s, border-color 0.15s, color 0.15s;
}
.btn-copy-source:hover { background: rgba(255,255,255,0.09); border-color: rgba(255,255,255,0.18); color: var(--text-mid); }
[data-theme="light"] .btn-copy-source { color: #374151; border-color: rgba(0,0,0,0.15); }
[data-theme="light"] .btn-copy-source:hover { background: rgba(0,0,0,0.06); border-color: rgba(0,0,0,0.25); color: #1f2937; }
.btn-copy-source.copied { background: rgba(16,185,129,0.12); border-color: rgba(16,185,129,0.35); color: #34d399; }

/* ── Stats (home page) ────────────────────────────────────────────── */
.stats-row {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 12px;
    margin: 0 0 22px;
}
.stat-card {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 18px 20px;
    position: relative;
    overflow: hidden;
}
.stat-card::before {
    content: "";
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 2px;
    background: linear-gradient(90deg, #4f46e5, #7c3aed);
    opacity: 0.7;
}
.stat-number {
    font-size: 32px;
    font-weight: 700;
    color: var(--text-hi);
    letter-spacing: -0.03em;
    line-height: 1;
    display: block;
    font-family: 'Sofia Sans', sans-serif;
}
.stat-label {
    color: var(--text-muted);
    font-size: 11px;
    text-transform: uppercase;
    letter-spacing: 0.07em;
    margin-top: 8px;
    display: block;
    font-weight: 600;
}

/* ── Homepage symbol index ────────────────────────────────────────── */
.index-section {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 20px 24px;
    margin-bottom: 14px;
}
.index-section-title {
    color: var(--text-hi);
    font-size: 13px;
    font-weight: 700;
    letter-spacing: 0.06em;
    text-transform: uppercase;
    margin: 0;
    padding: 0;
    display: flex;
    align-items: center;
    gap: 8px;
    cursor: pointer;
    user-select: none;
}
.index-section-title:hover { color: #a5b4fc; }
.index-section.open .index-section-title {
    margin-bottom: 12px;
    padding-bottom: 10px;
    border-bottom: 1px solid var(--border2);
}
.index-chevron {
    display: flex;
    align-items: center;
    color: var(--text-muted);
    transition: transform 0.15s;
}
.index-section.open .index-chevron { transform: rotate(90deg); }
.index-count {
    margin-left: auto;
    font-size: 11px;
    font-weight: 500;
    letter-spacing: 0;
    text-transform: none;
    color: var(--text-muted);
    background: var(--border2);
    border-radius: 10px;
    padding: 1px 8px;
}
.index-table { display: flex; flex-direction: column; gap: 2px; }
.index-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 7px 10px;
    border-radius: 7px;
    text-decoration: none;
    transition: background 0.1s;
    gap: 12px;
}
.index-row:hover { background: #1f2230; }
.index-symbol {
    font-size: 13px;
    font-weight: 600;
    color: #a5b4fc;
    font-family: 'JetBrains Mono', 'Fira Code', monospace;
    white-space: nowrap;
}
.index-file {
    font-size: 11px;
    color: var(--text-muted);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    text-align: right;
}
.index-file-dir { color: var(--text-dim); }

/* ── Directory index / project tree ───────────────────────────────── */
.directory-index, .main-tree {
    background: var(--surface);
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 22px 24px;
    margin-top: 12px;
}
.directory-index h1, .main-tree h2 {
    color: var(--text-hi);
    font-size: 16px;
    font-weight: 700;
    letter-spacing: -0.01em;
    margin-bottom: 14px;
    display: flex;
    align-items: center;
    gap: 8px;
}
.directory-index .icon, .main-tree .icon { color: #f59e0b; }
[data-theme="light"] .directory-index .icon, [data-theme="light"] .main-tree .icon { color: #cc5500; }

.tree { margin-left: 4px; }
.tree-item {
    padding: 7px 12px;
    margin: 4px 0;
    background: var(--surface2);
    border: 1px solid var(--border3);
    border-radius: 8px;
    transition: background 0.1s, border-color 0.1s;
    display: flex;
    align-items: center;
    gap: 8px;
}
.tree-item:hover { background: #1f2230; border-color: rgba(255,255,255,0.1); }
.tree-item a {
    color: var(--text-mid);
    text-decoration: none;
    font-size: 13px;
    flex: 1;
}
.tree-item a:hover { color: #fff; }
.tree-item .icon { color: #4f46e5; flex-shrink: 0; }
.tree-dir > .icon, .tree-dir-icon { color: #f59e0b; }
[data-theme="light"] .tree-dir > .icon, [data-theme="light"] .tree-dir-icon { color: #cc5500; }
.tree-dir .tree-children { margin-left: 18px; margin-top: 4px; }
.folder-toggle {
    color: var(--text-muted);
    cursor: pointer;
    user-select: none;
    display: inline-block;
    width: 12px;
    transition: transform 0.2s;
    font-size: 10px;
    flex-shrink: 0;
}
.folder-toggle.expanded { transform: rotate(90deg); color: #4f46e5; }

/* ── Status bar ───────────────────────────────────────────────────── */
.statusbar {
    height: 24px;
    flex-shrink: 0;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0 16px;
    background: #090b10;
    border-top: 1px solid var(--border3);
    font-size: 10px;
    color: var(--text-sep);
    font-family: Consolas, Menlo, Monaco, monospace;
}
.statusbar-left, .statusbar-right { display: flex; align-items: center; gap: 12px; }
.statusbar .pill { padding: 1px 7px; font-size: 9.5px; }
.status-dot {
    width: 6px;
    height: 6px;
    border-radius: 50%;
    background: #10b981;
    box-shadow: 0 0 6px rgba(16,185,129,0.5);
}

/* ── Language picker ──────────────────────────────────────────────── */
.language-picker { position: relative; }
.lang-current {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 4px 8px 4px 4px;
    background: var(--hover);
    border: 1px solid rgba(255,255,255,0.1);
    border-radius: 7px;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s;
}
.lang-current:hover { background: var(--border); border-color: rgba(255,255,255,0.16); }
[data-theme="light"] .lang-current .lang-name  { color: #d1d5db; }
[data-theme="light"] .lang-current .lang-arrow { color: #9ca3af; }
.lang-current svg { width: 22px; height: 14px; border-radius: 2px; }
.lang-name {
    color: var(--text-mid);
    font-size: 11px;
    white-space: nowrap;
    font-weight: 500;
}
.lang-arrow {
    color: var(--text-muted);
    font-size: 8px;
    margin-left: 2px;
    transition: transform 0.2s;
}
.lang-current.active .lang-arrow { transform: rotate(180deg); }
.lang-dropdown {
    position: absolute;
    top: calc(100% + 6px);
    right: 0;
    background: var(--surface);
    border: 1px solid rgba(255,255,255,0.1);
    border-radius: 8px;
    box-shadow: 0 12px 32px rgba(0,0,0,0.4);
    z-index: 1000;
    min-width: 160px;
    padding: 4px;
}
.lang-option {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 7px 9px;
    cursor: pointer;
    transition: background 0.15s;
    border-radius: 5px;
}
.lang-option:hover { background: var(--border2); }
.lang-option svg { width: 22px; height: 14px; border-radius: 2px; }

/* ── Modal (source viewer) ────────────────────────────────────────── */
.modal {
    display: none;
    position: fixed;
    z-index: 10000;
    inset: 0;
    background: rgba(0,0,0,0.72);
    backdrop-filter: blur(4px);
    -webkit-backdrop-filter: blur(4px);
    animation: fadeIn 0.18s;
}
@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
.modal-content {
    background: var(--surface);
    margin: 50px auto;
    padding: 0;
    border: 1px solid rgba(79,70,229,0.4);
    width: 92%;
    max-width: 1200px;
    max-height: 80vh;
    border-radius: 14px;
    box-shadow: 0 24px 64px rgba(0,0,0,0.5), 0 0 0 1px rgba(79,70,229,0.2);
    animation: slideDown 0.25s;
    overflow: hidden;
    display: flex;
    flex-direction: column;
}
@keyframes slideDown {
    from { transform: translateY(-30px); opacity: 0; }
    to { transform: translateY(0); opacity: 1; }
}
.modal-header {
    background: var(--bg);
    padding: 14px 20px;
    border-bottom: 1px solid var(--border);
    display: flex;
    flex-direction: column;
    gap: 4px;
    flex-shrink: 0;
    position: relative;
}
.modal-title-row {
    display: flex;
    align-items: center;
    gap: 10px;
    padding-right: 32px;
}
.modal-header h3 {
    margin: 0;
    color: var(--text-hi);
    font-size: 14px;
    font-weight: 700;
    letter-spacing: -0.01em;
    font-family: Consolas, Menlo, Monaco, monospace;
}
.modal-copy-btn {
    background: none;
    border: none;
    padding: 4px;
    cursor: pointer;
    color: var(--text-muted);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 5px;
    transition: background 0.15s, color 0.15s;
    flex-shrink: 0;
}
.modal-copy-btn:hover { background: var(--border2); color: var(--text-mid); }
.modal-copy-btn.copied { color: #34d399; }
.modal-header .file-info {
    color: var(--text-muted);
    font-size: 11px;
    font-family: Consolas, Menlo, Monaco, monospace;
}
.modal-close {
    color: var(--text-muted);
    font-size: 22px;
    cursor: pointer;
    background: none;
    border: none;
    padding: 0;
    width: 28px;
    height: 28px;
    line-height: 1;
    border-radius: 7px;
    transition: background 0.15s, color 0.15s;
    display: flex;
    align-items: center;
    justify-content: center;
    position: absolute;
    top: 12px;
    right: 16px;
}
.modal-close:hover { color: var(--text-mid); background: var(--border2); }
.modal-body {
    padding: 18px;
    overflow-y: auto;
    flex: 1;
}
.modal-body pre {
    margin: 0;
    background: var(--bg);
    color: var(--text);
    padding: 16px;
    border: 1px solid var(--border);
    border-radius: 10px;
    overflow-x: auto;
    font-family: Consolas, Menlo, Monaco, monospace;
    font-size: 12.5px;
    line-height: 1.65;
}
.modal-body pre code { color: var(--text); }
.loading { text-align: center; padding: 40px; color: var(--text-muted); font-size: 13px; }
.error { text-align: center; padding: 40px; color: #ef4444; font-size: 13px; }

/* ── RTL support ──────────────────────────────────────────────────── */
[dir="rtl"] .breadcrumb .separator { display: inline-block; transform: scaleX(-1); }
[dir="rtl"] .class { border-left: 1px solid var(--border); border-right: 3px solid #4f46e5; }
