<script>
const PHPDG_INDEX = {$searchIndexJson};
const PHPDG_ROOT = "{$rootPath}";
// ── i18n / language ──────────────────────────────────────────────────────────
const translations = $translationsJson;
const languages = $languagesJson;
const availableLanguages = $availableLanguagesJson;

let currentLang = localStorage.getItem('phpdg_lang') || '{$this->settings['language']}';

function applyTranslations() {
    const lang = translations[currentLang] || translations['en'];
    document.querySelectorAll('[data-i18n]').forEach(el => {
        const key = el.getAttribute('data-i18n');
        if (lang[key]) {
            el.textContent = lang[key];
        }
    });

    const searchBox = document.getElementById('search');
    if (searchBox && lang['GENERATOR_SEARCH_PLACEHOLDER']) {
        searchBox.placeholder = lang['GENERATOR_SEARCH_PLACEHOLDER'];
    }
    const sbSearch = document.getElementById('sidebarSearch');
    if (sbSearch && lang['GENERATOR_SEARCH_PLACEHOLDER']) {
        sbSearch.placeholder = lang['GENERATOR_SEARCH_PLACEHOLDER'];
    }
}

function changeLang(newLang) {
    currentLang = newLang;
    localStorage.setItem('phpdg_lang', newLang);

    const langData = languages[currentLang];
    if (langData && langData.direction) {
        document.documentElement.setAttribute('dir', langData.direction);
        document.documentElement.setAttribute('lang', newLang);
    }

    applyTranslations();
    updateLanguagePicker();
    toggleLanguagePicker();
}

function updateLanguagePicker() {
    const langData = languages[currentLang];
    if (!langData) return;

    const current = document.querySelector('.lang-current');
    if (!current) return;

    current.innerHTML = langData.flag +
        '<span class="lang-name">' + langData.native + '</span>' +
        '<span class="lang-arrow">▼</span>';

    const dropdown = document.getElementById('langDropdown');
    if (!dropdown) return;

    let dropdownHTML = '';
    availableLanguages.forEach(code => {
        if (code === currentLang) return;
        if (!languages[code]) return;
        const lang = languages[code];
        dropdownHTML += '<div class="lang-option" onclick="changeLang(\'' + code + '\')">' +
            lang.flag +
            '<span class="lang-name">' + lang.native + '</span>' +
            '</div>';
    });
    dropdown.innerHTML = dropdownHTML;
}

function toggleLanguagePicker() {
    const dropdown = document.getElementById('langDropdown');
    const current = document.querySelector('.lang-current');
    if (!dropdown || !current) return;
    if (dropdown.style.display === 'none' || dropdown.style.display === '') {
        dropdown.style.display = 'block';
        current.classList.add('active');
    } else {
        dropdown.style.display = 'none';
        current.classList.remove('active');
    }
}

document.addEventListener('click', function(e) {
    const picker = document.querySelector('.language-picker');
    if (picker && !picker.contains(e.target)) {
        const dropdown = document.getElementById('langDropdown');
        const current = document.querySelector('.lang-current');
        if (dropdown) dropdown.style.display = 'none';
        if (current) current.classList.remove('active');
    }
});

// ── Method / function expand ────────────────────────────────────────────────
function toggleMethod(id) {
    const details = document.getElementById(id);
    const icon = document.getElementById('icon-' + id);
    const wrapper = details ? details.parentElement : null;
    if (!details) return;

    const open = details.style.display !== 'block';
    details.style.display = open ? 'block' : 'none';
    if (icon) icon.classList.toggle('expanded', open);
    if (wrapper) wrapper.classList.toggle('is-open', open);
}

// Auto-open method/function targeted by hash (deep link from sidebar search)
function openHashTarget() {
    const hash = window.location.hash;
    if (!hash) return;
    const target = document.querySelector(hash);
    if (!target) return;
    if (target.classList.contains('method-item') || target.classList.contains('function')) {
        const details = target.querySelector('.method-details');
        if (details) toggleMethod(details.id);
    }
    setTimeout(() => target.scrollIntoView({behavior:'smooth', block:'start'}), 80);
}

// ── Project tree (legacy in-page) ───────────────────────────────────────────
function toggleFolder(element) {
    const treeItem = element.closest('.tree-item');
    if (!treeItem) return;
    const children = treeItem.querySelector('.tree-children');
    if (!children) return;
    const open = children.style.display === 'none' || children.style.display === '';
    children.style.display = open ? 'block' : 'none';
    element.classList.toggle('expanded', open);
}

// ── Homepage index section toggle ──────────────────────────────────────────
function phpdgToggleIndex(titleEl) {
    const section = titleEl.closest('.index-section');
    const table   = section.querySelector('.index-table');
    const open    = section.classList.toggle('open');
    table.style.display = open ? 'flex' : 'none';
}

// ── Sidebar dir toggle ──────────────────────────────────────────────────────
function phpdgToggleSbDir(el, event) {
    if (event) event.stopPropagation();
    const next = el.nextElementSibling;
    const open = !el.classList.contains('expanded');
    el.classList.toggle('expanded', open);
    if (next && next.classList.contains('sb-tree-children')) {
        next.style.display = open ? 'block' : 'none';
    }
}

// ── Sidebar search (uses inline PHPDG_INDEX, toggles tree/results) ──────────
function phpdgInitSidebarSearch() {
    const input = document.getElementById('sidebarSearch');
    const results = document.getElementById('sidebarSearchResults');
    const tree = document.getElementById('sidebarTree');
    if (!input || !results || !tree) return;
    if (typeof PHPDG_INDEX === 'undefined') return;

    const TYPE_BADGES = {
        F:  {color:'#4f46e5', label:'F'},
        C:  {color:'#4ec9b0', label:'C'},
        M:  {color:'#10b981', label:'M'},
        fn: {color:'#0ea5e9', label:'fn'},
    };

    const showResults = (items) => {
        tree.style.display = 'none';
        results.style.display = '';
        if (items.length === 0) {
            results.innerHTML = '<div class="sidebar-empty">—</div>';
            return;
        }
        let html = '';
        items.forEach(it => {
            const b = TYPE_BADGES[it.t] || TYPE_BADGES.F;
            const sub = it.c ? (it.c + ' · ' + it.p) : it.p;
            html += '<a class="sb-result" href="' + it.u + '">' +
                '<span style="display:inline-block;min-width:20px;font-size:9.5px;font-weight:700;color:' + b.color + ';font-family:Consolas,Menlo,Monaco,monospace;margin-right:8px;">' + b.label + '</span>' +
                '<span style="color:#e5e7eb;">' + escapeHtml(it.n) + '</span>' +
                '<span style="display:block;font-size:10px;color:#6b7280;margin-left:28px;margin-top:2px;font-family:Consolas,Menlo,Monaco,monospace;">' + escapeHtml(sub) + '</span>' +
                '</a>';
        });
        results.innerHTML = html;
    };

    const showTree = () => {
        results.style.display = 'none';
        results.innerHTML = '';
        tree.style.display = '';
    };

    let timer = null;
    input.addEventListener('input', e => {
        clearTimeout(timer);
        timer = setTimeout(() => {
            const q = e.target.value.toLowerCase().trim();
            if (q === '') { showTree(); return; }
            const filtered = PHPDG_INDEX.filter(it =>
                it.n.toLowerCase().includes(q) ||
                (it.c && it.c.toLowerCase().includes(q)) ||
                it.p.toLowerCase().includes(q)
            ).slice(0, 80);
            showResults(filtered);
        }, 80);
    });
}

// ── Init ────────────────────────────────────────────────────────────────────
applyTranslations();
updateLanguagePicker();

const initialLangData = languages[currentLang];
if (initialLangData && initialLangData.direction) {
    document.documentElement.setAttribute('dir', initialLangData.direction);
    document.documentElement.setAttribute('lang', currentLang);
}

phpdgInitSidebarSearch();
window.addEventListener('load', openHashTarget);
window.addEventListener('hashchange', openHashTarget);

// ── Copy source helpers ──────────────────────────────────────────────────────
const COPY_SVG  = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" width="13" height="13"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg>`;
const CHECK_SVG = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" width="13" height="13"><polyline points="4 12 9 17 20 7"/></svg>`;

function flashCopied(btn, isIconOnly) {
    const orig = btn.innerHTML;
    btn.innerHTML = isIconOnly
        ? CHECK_SVG.replace('width="13"', 'width="15"').replace('height="13"', 'height="15"')
        : CHECK_SVG + ' Copied';
    btn.disabled = true;
    btn.classList.add('copied');
    setTimeout(() => { btn.innerHTML = orig; btn.disabled = false; btn.classList.remove('copied'); }, 3000);
}

function copySource(fileId, lineStart, lineEnd, btn) {
    const url = '{$generatorPath}?action=get_source&file_id=' + encodeURIComponent(fileId) + '&line_start=' + lineStart + '&line_end=' + lineEnd;
    fetch(url)
        .then(r => r.ok ? r.text() : Promise.reject('HTTP ' + r.status))
        .then(text => JSON.parse(text))
        .then(data => { if (data.success) navigator.clipboard.writeText(data.source).then(() => flashCopied(btn, false)); })
        .catch(() => {});
}

function copyModalSource(btn) {
    const code = document.querySelector('#modalBody pre code');
    if (!code) return;
    navigator.clipboard.writeText(code.textContent).then(() => flashCopied(btn, true));
}

// ── AJAX Source Code Viewer ──────────────────────────────────────────────────
function viewSource(fileId, lineStart, lineEnd, functionName) {
    let modal = document.getElementById('sourceModal');
    if (!modal) {
        modal = document.createElement('div');
        modal.id = 'sourceModal';
        modal.className = 'modal';
        modal.innerHTML =
            '<div class="modal-content">' +
                '<div class="modal-header">' +
                    '<div class="modal-title-row">' +
                        '<h3 id="modalTitle">Loading...</h3>' +
                        '<button class="modal-copy-btn" onclick="copyModalSource(this)" title="Copy source"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round" width="15" height="15"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"/></svg></button>' +
                    '</div>' +
                    '<span class="file-info" id="modalFileInfo"></span>' +
                    '<button class="modal-close" onclick="closeSourceModal()">&times;</button>' +
                '</div>' +
                '<div class="modal-body" id="modalBody">' +
                    '<div class="loading">Loading source code...</div>' +
                '</div>' +
            '</div>';
        document.body.appendChild(modal);

        modal.onclick = function(event) {
            if (event.target === modal) {
                closeSourceModal();
            }
        };
    }

    modal.style.display = 'block';

    document.getElementById('modalTitle').textContent = functionName + '()';
    document.getElementById('modalFileInfo').textContent = '';
    document.getElementById('modalBody').innerHTML = '<div class="loading">Loading source code...</div>';

    const url = '{$generatorPath}?action=get_source&file_id=' + encodeURIComponent(fileId) + '&line_start=' + lineStart + '&line_end=' + lineEnd;

    fetch(url)
        .then(response => {
            if (!response.ok) {
                throw new Error('generator.php not reachable (HTTP ' + response.status + '). Place generator.php next to your output folder.');
            }
            return response.text();
        })
        .then(text => {
            let data;
            try { data = JSON.parse(text); } catch(e) {
                throw new Error('generator.php returned non-JSON. Make sure it is a PHP file served by a PHP server.');
            }
            if (data.success) {
                document.getElementById('modalFileInfo').textContent =
                    `\${data.file} (lines \${data.lines})`;
                document.getElementById('modalBody').innerHTML =
                    `<pre><code>\${escapeHtml(data.source)}</code></pre>`;
            } else {
                document.getElementById('modalBody').innerHTML =
                    `<div class="error">\${data.error || 'Failed to load source code'}</div>`;
            }
        })
        .catch(error => {
            document.getElementById('modalBody').innerHTML =
                `<div class="error">\${error.message}</div>`;
        });
}

function closeSourceModal() {
    const modal = document.getElementById('sourceModal');
    if (modal) {
        modal.style.display = 'none';
    }
}

function escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

document.addEventListener('keydown', function(event) {
    if (event.key === 'Escape') {
        closeSourceModal();
    }
});


function phpdgToggleTheme() {
  var html  = document.documentElement;
  var theme = html.getAttribute('data-theme') === 'dark' ? 'light' : 'dark';
  html.setAttribute('data-theme', theme);
  localStorage.setItem('phpdg-theme', theme);
}
