    private function buildSearchIndexJson($rootPath)
    {
        $entries = [];
        foreach ($this->documentation as $file => $doc) {
            $rel = $this->getRelativePath($file);
            $url = str_replace('.php', '_php', $rel) . '.html';
            $entries[] = ['t' => 'F', 'n' => basename($file), 'p' => $rel, 'u' => $rootPath . $url];
            foreach ($doc['classes'] as $cls) {
                $entries[] = ['t' => 'C', 'n' => $cls['name'], 'p' => $rel, 'u' => $rootPath . $url . '#class-' . preg_replace('/[^a-zA-Z0-9_-]/', '', $cls['name'])];
                foreach ($cls['methods'] as $i => $m) {
                    $mid = 'method-' . preg_replace('/[^a-zA-Z0-9_-]/', '', $cls['name']) . '-' . $i;
                    $entries[] = ['t' => 'M', 'n' => $m['name'], 'c' => $cls['name'], 'p' => $rel, 'u' => $rootPath . $url . '#' . $mid];
                }
            }
            foreach ($doc['functions'] as $i => $fn) {
                $entries[] = ['t' => 'fn', 'n' => $fn['name'], 'p' => $rel, 'u' => $rootPath . $url . '#func-' . $i];
            }
        }
        return json_encode($entries, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
    }
}// ===== EXECUTION =====
// Run generator when:
// 1. Direct access (no params)
// 2. AJAX generation request (?generate=1) — streams SSE progress
// Skip execution only in ggui UI mode (?ggui=1)

if (!isset($_GET['ggui']) && !defined('PHPDG_NO_AUTORUN')) {
    $isAjax = isset($_GET['generate']) && $_GET['generate'] === '1';

    if ($isAjax) {
        // SSE streaming setup
        while (ob_get_level() > 0) { @ob_end_clean(); }
        header('Content-Type: text/event-stream');
        header('Cache-Control: no-cache, no-transform');
        header('X-Accel-Buffering: no');
        ignore_user_abort(true);
        @ini_set('zlib.output_compression', '0');
        @ini_set('output_buffering', '0');
        @ini_set('implicit_flush', '1');

        $generator = new phpDocGenerator($settings, $translations, $languages);
        $generator->sseMode = true;

        try {
            $generator->generate();
            echo "event: done\ndata: " . json_encode(['success' => true]) . "\n\n";
        } catch (Exception $e) {
            echo "event: error\ndata: " . json_encode(['error' => $e->getMessage()]) . "\n\n";
        }
        @ob_flush();
        @flush();
        exit;
    }

    // Non-AJAX: original behavior (CLI or direct browser hit)
    $generator = new phpDocGenerator($settings, $translations, $languages);
    $generator->generate();
}
