                transition: width 0.3s ease;
            }
            .progress-text {
                color: #4f46e5;
                font-size: 11px;
                font-family: Consolas, Menlo, Monaco, monospace;
            }
            .ggui-buttons {
                display: flex;
                gap: 10px;
            }
            .ggui-btn {
                flex: 1;
                padding: 10px 20px;
                border: none;
                border-radius: 8px;
                font-family: 'Sofia Sans', sans-serif;
                font-size: 13px;
                font-weight: 600;
                cursor: pointer;
                transition: background 0.15s;
            }
            .ggui-btn-close {
                background: rgba(255,255,255,0.06);
                color: #9ca3af;
                border: 1px solid rgba(255,255,255,0.08);
            }
            .ggui-btn-close:hover {
                background: rgba(255,255,255,0.1);
                color: #d4d4d4;
            }
            .ggui-btn-open {
                background: #4f46e5;
                color: #ffffff;
            }
            .ggui-btn-open:hover {
                background: #4338ca;
            }
        </style>
    </head>
    <body>
    <div class="ggui-container">
        <div class="ggui-logo">
            <?= LOGO_SVG; ?>
        </div>

        <div class="ggui-file-count">
            Found <span id="fileCount">0</span> PHP files
        </div>

        <div class="ggui-steps" id="stepsContainer">
            <!-- Steps will be added dynamically -->
        </div>

        <div class="ggui-buttons" id="buttonContainer" style="display: none;">
            <button class="ggui-btn ggui-btn-close" onclick="closeWindow()">Close window</button>
            <button class="ggui-btn ggui-btn-open" onclick="openDocumentation()">Open documentation</button>
        </div>
    </div>

    <script>
        /* ========= GGUI-ONLY JAVASCRIPT ========= */
        let GGUI_TOTAL_FILES = 0;
        let generationStarted = false;

        const STEP_LABELS = {
            'scan': 'Scanning directories',
            'parsing': 'Analyzing PHP files',
            'tree': 'Building tree structure',
            'structure': 'Creating directory structure',
            'html': 'Generating HTML files',
            'dir-index': 'Generating directory indexes',
            'main-index': 'Generating main index.html',
            'htaccess': 'Creating .htaccess',
            'json-index': 'Generating JSON file index'
        };

        let currentStepKey = null;
        let currentStepEl = null;
        let currentProgressBar = null;
        let currentProgressText = null;

        function initGgui() {
            fetch('?action=get_file_count')
                .then(response => response.json())
                .then(data => {
                    GGUI_TOTAL_FILES = data.count;
                    animateGguiFileCount();
                    if (!generationStarted) {
                        generationStarted = true;
                        startSSEGeneration();
                    }
                })
                .catch(err => {
                    console.error('Error getting file count:', err);
                    GGUI_TOTAL_FILES = 0;
                    if (!generationStarted) {
                        generationStarted = true;
                        startSSEGeneration();
                    }
                });
        }

        function animateGguiFileCount() {
            let count = 0;
            const increment = Math.max(1, Math.ceil(GGUI_TOTAL_FILES / 30));
            const interval = setInterval(() => {
                count += increment;
                if (count >= GGUI_TOTAL_FILES) {
                    count = GGUI_TOTAL_FILES;
                    clearInterval(interval);
                }
                const countEl = document.getElementById('fileCount');
                if (countEl) countEl.textContent = count;
            }, 30);
        }

        function closeCurrentStep() {
            if (!currentStepEl) return;
            currentStepEl.classList.remove('active');
            currentStepEl.classList.add('done');
            if (currentProgressText) {
                currentProgressText.textContent = 'Done!';
                currentProgressText.style.color = '#ffffff';
            }
            if (currentProgressBar) currentProgressBar.style.display = 'none';
            currentStepEl = null;
            currentProgressBar = null;
            currentProgressText = null;
        }

        function openStep(key, label) {
            const container = document.getElementById('stepsContainer');
            if (!container) return;

            currentStepKey = key;
            currentStepEl = document.createElement('div');
            currentStepEl.className = 'ggui-step active';
            currentStepEl.innerHTML = label + ' - <span class="progress-text">0%</span>';
            container.appendChild(currentStepEl);

            currentProgressBar = document.createElement('div');
            currentProgressBar.className = 'ggui-progress-bar';
            currentProgressBar.innerHTML = '<div class="bar"></div>';
            container.appendChild(currentProgressBar);

            currentProgressText = currentStepEl.querySelector('.progress-text');
        }

        function updateStep(pct) {
            if (!currentStepEl || !currentProgressBar || !currentProgressText) return;
            const bar = currentProgressBar.querySelector('.bar');
            bar.style.width = pct + '%';
            currentProgressText.textContent = pct + '%';
        }

        function startSSEGeneration() {
            const es = new EventSource(window.location.pathname + '?generate=1');

            es.addEventListener('progress', (e) => {
                let data;
                try { data = JSON.parse(e.data); } catch (err) { return; }
                const label = STEP_LABELS[data.step] || data.step;

                if (currentStepKey !== data.step) {
                    closeCurrentStep();
                    openStep(data.step, label);
                }
                updateStep(data.pct);
            });

            es.addEventListener('done', () => {
                closeCurrentStep();
                es.close();
                showGguiCompletion();
            });

            es.addEventListener('error', (e) => {
                console.error('SSE connection error', e);
                // EventSource auto-reconnects by default; close to prevent loops when done
                if (es.readyState === EventSource.CLOSED) return;
            });
        }

        // Show completion buttons
        function showGguiCompletion() {
            const buttonContainer = document.getElementById('buttonContainer');
            if (buttonContainer) {
                buttonContainer.style.display = 'flex';

                // Auto-redirect after 2 seconds
                setTimeout(() => {
                    openDocumentation();
                }, 20000000);
            }
        }

        // Close window
        function closeWindow() {
            window.close();
            setTimeout(() => {
                if (!window.closed) {
                    window.location.href = 'about:blank';
                }
            }, 100);
        }

        // Open documentation (WITHOUT language parameter)
        function openDocumentation() {
            // Always use clean URL without parameters
            const docUrl = '<?= $settings['output_dir']; ?>/index.html';

            if (window.opener) {
                window.opener.location.href = docUrl;
                window.close();
            } else {
                window.location.href = docUrl;
            }
        }

        // Start when DOM is ready
        if (document.readyState === 'loading') {
            document.addEventListener('DOMContentLoaded', initGgui);
        } else {
            initGgui();
        }
    </script>
    </body>
    </html>
    <?php
    exit;
}